-- Testimonials
insert into testimonials (id, author_name, author_location, avatar_url, quote, rating) values ('testimonial-1', 'Charlotte Reed', 'London, UK', 'https://randomuser.me/api/portraits/women/61.jpg', 'LUMA doesn''t feel like booking a rental — it feels like being handed the keys to someone''s most beautiful home.', 5);
insert into testimonials (id, author_name, author_location, avatar_url, quote, rating) values ('testimonial-2', 'Marcus Lindqvist', 'Stockholm, Sweden', 'https://randomuser.me/api/portraits/men/62.jpg', 'The concierge arranged everything before we even landed. Effortless, from the first email to checkout.', 5);
insert into testimonials (id, author_name, author_location, avatar_url, quote, rating) values ('testimonial-3', 'Amira Haddad', 'Dubai, UAE', 'https://randomuser.me/api/portraits/women/63.jpg', 'Every property we''ve stayed in has had a real point of view. Nothing generic, nothing rushed.', 4.9);
insert into testimonials (id, author_name, author_location, avatar_url, quote, rating) values ('testimonial-4', 'Thomas Berger', 'Zurich, Switzerland', 'https://randomuser.me/api/portraits/men/64.jpg', 'Privacy, design, and a level of service I''ve only otherwise found at five-star hotels.', 5);
insert into testimonials (id, author_name, author_location, avatar_url, quote, rating) values ('testimonial-5', 'Isabelle Laurent', 'Paris, France', 'https://randomuser.me/api/portraits/women/65.jpg', 'We''ve booked LUMA three times now for family trips. It''s become the standard we compare everything else to.', 4.95);
insert into testimonials (id, author_name, author_location, avatar_url, quote, rating) values ('testimonial-6', 'Daniel Osei', 'Toronto, Canada', 'https://randomuser.me/api/portraits/men/66.jpg', 'Quietly extraordinary. The kind of stay that makes the destination feel entirely your own.', 5);

-- FAQs
insert into faqs (id, question, answer, sort_order) values ('faq-1', 'How are LUMA homes selected?', 'Every residence is visited and personally curated by our team before it joins the collection. We look for design, privacy, quality of construction, and a genuine sense of place — not just square footage.', 0);
insert into faqs (id, question, answer, sort_order) values ('faq-2', 'What does the concierge service include?', 'Our concierge is available around the clock before and during your stay — from arranging airport transfers and private chefs to restaurant reservations and local experiences tailored to you.', 1);
insert into faqs (id, question, answer, sort_order) values ('faq-3', 'Can I cancel or change my reservation?', 'Cancellation terms vary by property and are shown clearly before you book. Our team can also help you adjust dates or find an alternative home where possible.', 2);
insert into faqs (id, question, answer, sort_order) values ('faq-4', 'Is a security deposit required?', 'Most homes require a refundable security deposit, held securely and released shortly after checkout provided the home is left in good condition.', 3);
insert into faqs (id, question, answer, sort_order) values ('faq-5', 'Do you offer instant booking?', 'Select homes support instant booking, shown with a badge in search results. Others are confirmed by our team within a few hours to make sure every detail is right for your stay.', 4);
insert into faqs (id, question, answer, sort_order) values ('faq-6', 'What is included in the nightly price?', 'The nightly rate covers the home itself. Cleaning fees and any applicable taxes are shown separately at checkout, with no hidden charges added later.', 5);
